// Encoding/Hashing-Werkzeug. operation: base64-encode|base64-decode|url-encode|url-decode|sha-256|sha-1|jwt-decode
async function run(input) {
  const op = String((input && input.operation) || '').toLowerCase();
  const text = String((input && input.text) || '');
  const enc = new TextEncoder();
  async function sha(algo) {
    const buf = await crypto.subtle.digest(algo, enc.encode(text));
    return Array.from(new Uint8Array(buf)).map(function (b) { return b.toString(16).padStart(2, '0'); }).join('');
  }
  function b64dec(s) { return decodeURIComponent(escape(atob(s.replace(/-/g, '+').replace(/_/g, '/')))); }
  switch (op) {
    case 'base64-encode': return { ergebnis: btoa(unescape(encodeURIComponent(text))) };
    case 'base64-decode': return { ergebnis: b64dec(text) };
    case 'url-encode': return { ergebnis: encodeURIComponent(text) };
    case 'url-decode': return { ergebnis: decodeURIComponent(text) };
    case 'sha-256': return { ergebnis: await sha('SHA-256') };
    case 'sha-1': return { ergebnis: await sha('SHA-1') };
    case 'jwt-decode': {
      const parts = text.split('.');
      if (parts.length < 2) return { fehler: 'Kein gueltiges JWT (header.payload.signature).' };
      try { return { header: JSON.parse(b64dec(parts[0])), payload: JSON.parse(b64dec(parts[1])) }; }
      catch (e) { return { fehler: 'JWT konnte nicht dekodiert werden.' }; }
    }
    default: return { fehler: 'Unbekannte Operation. Erlaubt: base64-encode, base64-decode, url-encode, url-decode, sha-256, sha-1, jwt-decode.' };
  }
}
